import React, { useEffect, useState } from 'react';
import { getCurrentUser, listIssues, listNotifs } from '../../services/mockApi';
import { useNavigate } from 'react-router-dom';

export default function ForYou() {
  const navigate = useNavigate();
  const [user, setUser] = useState(getCurrentUser());
  const [issues, setIssues] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [showTodayOnly, setShowTodayOnly] = useState(false);
  const [hoveredButton, setHoveredButton] = useState(null);

  useEffect(() => {
    listIssues().then((res) => {
      if (Array.isArray(res)) {
        setIssues(res);
      } else if (res?.data && Array.isArray(res.data)) {
        setIssues(res.data);
      } else {
        setIssues([]);
      }
    });

    listNotifs().then((res) => {
      if (Array.isArray(res)) {
        setNotifications(res);
      } else if (res?.data && Array.isArray(res.data)) {
        setNotifications(res.data);
      } else {
        setNotifications([]);
      }
    });
  }, []);

  const mine = Array.isArray(issues)
    ? issues.filter((i) => i.assignee === user?.id)
    : [];

  const today = new Date().toISOString().slice(0, 10);
  const thisWeek = new Date();
  thisWeek.setDate(thisWeek.getDate() + 7);
  const weekEnd = thisWeek.toISOString().slice(0, 10);

  const filteredIssues = mine.filter((i) => {
    if (!i.dueDate) return false;
    if (showTodayOnly) return i.dueDate === today;
    return i.dueDate >= today && i.dueDate <= weekEnd;
  });

  // Modern gradient background similar to popular dashboards
  const containerStyle = { 
    padding: '2rem', 
    fontFamily: "'Inter', 'Segoe UI', -apple-system, BlinkMacSystemFont, sans-serif", 
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    minHeight: '100vh',
    color: '#333'
  };

  const contentStyle = {
    maxWidth: '1200px',
    margin: '0 auto'
  };

  const headerStyle = { 
    marginBottom: '2rem',
    color: 'white'
  };

  const titleStyle = {
    fontSize: '2.5rem',
    fontWeight: '700',
    color: 'white',
    marginBottom: '0.5rem',
    background: 'linear-gradient(45deg, #fff, #f0f0f0)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    backgroundClip: 'text'
  };

  const subtitleStyle = {
    fontSize: '1.1rem',
    color: 'rgba(255, 255, 255, 0.8)',
    margin: 0,
    fontWeight: '400'
  };

  const gridStyle = { 
    display: 'grid', 
    gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', 
    gap: '1.5rem' 
  };

  const cardStyle = { 
    background: 'rgba(255, 255, 255, 0.95)',
    backdropFilter: 'blur(10px)',
    borderRadius: '16px', 
    padding: '1.75rem', 
    boxShadow: '0 8px 32px rgba(0, 0, 0, 0.1)',
    border: '1px solid rgba(255, 255, 255, 0.2)',
    transition: 'transform 0.2s ease, box-shadow 0.2s ease'
  };

  const cardHoverStyle = {
    transform: 'translateY(-4px)',
    boxShadow: '0 12px 40px rgba(0, 0, 0, 0.15)'
  };

  const cardTitleStyle = {
    fontSize: '1.3rem',
    fontWeight: '600',
    color: '#2d3748',
    marginBottom: '1.25rem',
    display: 'flex',
    alignItems: 'center',
    gap: '0.75rem'
  };

  const iconStyle = {
    fontSize: '1.5rem',
    width: '40px',
    height: '40px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'linear-gradient(135deg, #667eea, #764ba2)',
    borderRadius: '10px',
    color: 'white'
  };

  const btnStyle = { 
    background: 'linear-gradient(135deg, #667eea, #764ba2)',
    color: 'white', 
    padding: '0.875rem 1.25rem', 
    borderRadius: '12px', 
    textAlign: 'center',
    marginBottom: '0.875rem', 
    cursor: 'pointer', 
    border: 'none',
    fontSize: '1rem',
    fontWeight: '500',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '0.75rem',
    width: '100%',
    transition: 'all 0.3s ease',
    boxShadow: '0 4px 15px rgba(102, 126, 234, 0.3)'
  };

  const btnHoverStyle = {
    transform: 'translateY(-2px)',
    boxShadow: '0 6px 20px rgba(102, 126, 234, 0.4)'
  };

  const statusStyle = (status) => ({
    fontSize: '0.75rem',
    padding: '0.4rem 0.75rem',
    borderRadius: '20px',
    fontWeight: '600',
    background: status === 'Open' 
      ? 'linear-gradient(135deg, #48bb78, #38a169)' 
      : 'linear-gradient(135deg, #ed8936, #dd6b20)',
    color: 'white',
    textTransform: 'uppercase',
    letterSpacing: '0.5px'
  });

  const checkboxStyle = {
    marginRight: '0.75rem',
    width: '18px',
    height: '18px',
    accentColor: '#667eea'
  };

  const checkboxLabelStyle = {
    fontSize: '0.9rem',
    color: '#4a5568',
    display: 'flex',
    alignItems: 'center',
    fontWeight: '500'
  };

  const taskItemStyle = {
    padding: '1rem 0', 
    borderBottom: '1px solid #e2e8f0',
    display: 'flex',
    flexDirection: 'column',
    transition: 'background-color 0.2s ease'
  };

  const taskItemHoverStyle = {
    backgroundColor: '#f7fafc',
    borderRadius: '8px',
    padding: '1rem'
  };

  return (
    <div style={containerStyle}>
      <div style={contentStyle}>
        <div style={headerStyle}>
          <h1 style={titleStyle}>Welcome back, {user?.name}!</h1>
          <p style={subtitleStyle}>Here's what's happening with your projects this week</p>
        </div>

        <div style={gridStyle}>
          {/* Your Boards Section */}
          <div 
            style={cardStyle}
            onMouseEnter={(e) => Object.assign(e.target.style, cardHoverStyle)}
            onMouseLeave={(e) => Object.assign(e.target.style, cardStyle)}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
              <h2 style={cardTitleStyle}>
                <span style={iconStyle}>🗂️</span> 
                Your Boards
              </h2>
              <label style={checkboxLabelStyle}>
                <input
                  type="checkbox"
                  checked={showTodayOnly}
                  onChange={() => setShowTodayOnly(!showTodayOnly)}
                  style={checkboxStyle}
                />
                Show only today's
              </label>
            </div>
            <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
              {filteredIssues.length > 0 ? (
                filteredIssues.map((i, index) => (
                  <li 
                    key={i.id} 
                    style={taskItemStyle}
                    onMouseEnter={(e) => Object.assign(e.target.style, taskItemHoverStyle)}
                    onMouseLeave={(e) => Object.assign(e.target.style, taskItemStyle)}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.5rem' }}>
                      <strong style={{ fontSize: '0.95rem', color: '#2d3748', lineHeight: '1.4' }}>{i.title}</strong>
                      <span style={statusStyle(i.status)}>{i.status}</span>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <span style={{ fontSize: '0.8rem', color: '#718096' }}>Due: {i.dueDate}</span>
                      <span style={{ fontSize: '0.75rem', color: '#a0aec0', background: '#edf2f7', padding: '0.2rem 0.5rem', borderRadius: '4px' }}>
                        Priority: {i.priority || 'Medium'}
                      </span>
                    </div>
                  </li>
                ))
              ) : (
                <li style={{ 
                  color: '#a0aec0', 
                  fontStyle: 'italic', 
                  padding: '2rem 0', 
                  textAlign: 'center',
                  background: '#f7fafc',
                  borderRadius: '8px',
                  marginTop: '0.5rem'
                }}>
                  No tasks found for the selected period
                </li>
              )}
            </ul>
          </div>

          {/* Recently Viewed Section */}
          <div 
            style={cardStyle}
            onMouseEnter={(e) => Object.assign(e.target.style, cardHoverStyle)}
            onMouseLeave={(e) => Object.assign(e.target.style, cardStyle)}
          >
            <h2 style={cardTitleStyle}>
              <span style={iconStyle}>🕵️</span> 
              Recently Viewed
            </h2>
            <div style={{ 
              color: '#a0aec0', 
              fontSize: '0.9rem', 
              textAlign: 'center', 
              padding: '3rem 1rem',
              background: '#f7fafc',
              borderRadius: '12px',
              border: '2px dashed #e2e8f0'
            }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🔍</div>
              <p style={{ margin: 0, fontWeight: '500' }}>No recent items</p>
              <p style={{ margin: '0.5rem 0 0 0', fontSize: '0.8rem' }}>Projects you view will appear here</p>
            </div>
          </div>

          {/* Quick Actions Section */}
          <div 
            style={cardStyle}
            onMouseEnter={(e) => Object.assign(e.target.style, cardHoverStyle)}
            onMouseLeave={(e) => Object.assign(e.target.style, cardStyle)}
          >
            <h2 style={cardTitleStyle}>
              <span style={iconStyle}>⚡</span> 
              Quick Actions
            </h2>
            <div style={{ display: 'flex', flexDirection: 'column', marginTop: '0.5rem' }}>
              <button 
                style={{
                  ...btnStyle,
                  ...(hoveredButton === 'createProject' ? btnHoverStyle : {})
                }}
                onMouseEnter={() => setHoveredButton('createProject')}
                onMouseLeave={() => setHoveredButton(null)}
                onClick={() => navigate('/projects')}
              >
                <span style={{ fontSize: '1.2rem' }}>📁</span> 
                Create New Project
              </button>

              <button 
                style={{
                  ...btnStyle,
                  background: 'linear-gradient(135deg, #48bb78, #38a169)',
                  boxShadow: '0 4px 15px rgba(72, 187, 120, 0.3)',
                  ...(hoveredButton === 'createTask' ? btnHoverStyle : {})
                }}
                onMouseEnter={() => setHoveredButton('createTask')}
                onMouseLeave={() => setHoveredButton(null)}
                onClick={() => navigate('/issues/new')}
              >
                <span style={{ fontSize: '1.2rem' }}>✅</span> 
                Create New Task
              </button>

              <button 
                style={{
                  ...btnStyle,
                  background: 'linear-gradient(135deg, #ed8936, #dd6b20)',
                  boxShadow: '0 4px 15px rgba(237, 137, 54, 0.3)',
                  ...(hoveredButton === 'viewReports' ? btnHoverStyle : {})
                }}
                onMouseEnter={() => setHoveredButton('viewReports')}
                onMouseLeave={() => setHoveredButton(null)}
                onClick={() => navigate('/reports')}
              >
                <span style={{ fontSize: '1.2rem' }}>📊</span> 
                View Reports
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
